<?php declare(strict_types=1); namespace Database\Factories; use App\Domains\Events\Models\Event; use Illuminate\Database\Eloquent\Factories\Factory; use Illuminate\Support\Str; use Illuminate\Support\Facades\DB; final class EventFactory extends Factory { protected $model = Event::class; public function definition(): array { $venueId = DB::table("venues")->value("id"); if (!$venueId) { $venueId = DB::table("venues")->insertGetId(["name"=>"Test", "address"=>"Test", "correlation_id"=>Str::uuid()]); } return [ "venue_id" => $venueId, "title" => fake()->sentence(), "description" => fake()->paragraph(), "start_at" => fake()->dateTimeBetween("now", "+30 days"), "end_at" => fake()->dateTimeBetween("+31 days", "+60 days"), "status" => "draft", "seating_data" => json_encode(["capacity" => 100]), "correlation_id" => (string) Str::uuid() ]; } }
